function _cancelOrder(address nftAddress, uint256 assetId) internal returns (Order memory) {
  address sender = _msgSender();
  Order memory order = orderByAssetId[nftAddress][assetId];

  require(order.id != 0, "Asset not published");
  require(order.seller == sender || sender == owner(), "Unauthorized user");

  bytes32 orderId = order.id;
  address orderSeller = order.seller;
  address orderNftAddress = order.nftAddress;
  delete orderByAssetId[nftAddress][assetId];

  emit OrderCancelled(
    orderId,
    assetId,
    orderSeller,
    orderNftAddress
  );

  return order;
}

function _initialize(
    address _defaultAdmin,
    address _nodeOperatorManager,
    address _feeRecipient,
    uint256 _feeRate,
    uint256 _confirmExpiry
) internal {
    _requireNotZero(_nodeOperatorManager);

    super._initialize(_defaultAdmin, _confirmExpiry);

    _setFeeRate(_feeRate);
    _setFeeRecipient(_feeRecipient);

    _grantRole(NODE_OPERATOR_MANAGER_ROLE, _nodeOperatorManager);
    _setRoleAdmin(NODE_OPERATOR_MANAGER_ROLE, NODE_OPERATOR_MANAGER_ROLE);
    _setRoleAdmin(NODE_OPERATOR_FEE_EXEMPT_ROLE, NODE_OPERATOR_MANAGER_ROLE);
    _setRoleAdmin(NODE_OPERATOR_UNGUARANTEED_DEPOSIT_ROLE, NODE_OPERATOR_MANAGER_ROLE);
    _setRoleAdmin(NODE_OPERATOR_PROVE_UNKNOWN_VALIDATOR_ROLE, NODE_OPERATOR_MANAGER_ROLE);
}

function royaltyInfo(
    uint256 tokenId,
    uint256 salePrice
) public view virtual returns (address receiver, uint256 amount) {
    ERC2981Storage storage $ = _getERC2981Storage();
    RoyaltyInfo storage _royaltyInfo = $._tokenRoyaltyInfo[tokenId];
    address royaltyReceiver = _royaltyInfo.receiver;
    uint96 royaltyFraction = _royaltyInfo.royaltyFraction;

    if (royaltyReceiver == address(0)) {
        royaltyReceiver = $._defaultRoyaltyInfo.receiver;
        royaltyFraction = $._defaultRoyaltyInfo.royaltyFraction;
    }

    uint256 royaltyAmount = (salePrice * royaltyFraction) / _feeDenominator();

    return (royaltyReceiver, royaltyAmount);
}

function _checkCanCall(address caller, bytes calldata data) internal virtual {
    AccessManagedStorage storage $ = _getAccessManagedStorage();
    (bool immediate, uint32 delay) = AuthorityUtils.canCallWithDelay(
        authority(),
        caller,
        address(this),
        bytes4(data[0:4])
    );
    if (!immediate) {
        if (delay > 0) {
            $._consumingSchedule = true;
            IAccessManager(authority()).consumeScheduledOp(caller, data);
            $._consumingSchedule = false;
        } else {
            revert AccessManagedUnauthorized(caller);
        }
    }
}

function _release(IERC20Upgradeable token, address account) internal returns (uint256) {
    require(shares(account) > 0, "PaymentSplitter: account has no shares");

    uint256 totalReceived = token.balanceOf(address(this)) + totalReleased(token);
    uint256 payment = _pendingPayment(account, totalReceived, released(token, account));

    if (payment == 0) {
        return 0;
    }

    _erc20Released[token][account] += payment;
    _erc20TotalReleased[token] += payment;

    SafeERC20Upgradeable.safeTransfer(token, account, payment);
    emit ERC20PaymentReleased(token, account, payment);

    return payment;
}

function _transfer(address sender, address recipient, uint256 amount) internal virtual {
    require(sender != address(0), "ERC20: transfer from the zero address");
    require(recipient != address(0), "ERC20: transfer to the zero address");

    _beforeTokenTransfer(sender, recipient, amount);

    uint256 senderBalance = _balances[sender];
    require(senderBalance >= amount, "ERC20: transfer amount exceeds balance");
    unchecked {
        _balances[sender] = senderBalance - amount;
    }
    _balances[recipient] += amount;

    emit Transfer(sender, recipient, amount);
}

function registerBalance() external {
  require(!registeredBalance[msg.sender], "Register Balance::The user is already registered");

  // Get balance of the sender
  uint256 currentBalance = estateLandBalance.balanceOf(msg.sender);
  if (currentBalance > 0) {
    require(
      estateLandBalance.destroyTokens(msg.sender, currentBalance),
      "Register Balance::Could not destroy tokens"
    );
  }

  // Set balance as registered
  registeredBalance[msg.sender] = true;

  // Get LAND balance
  uint256 newBalance = getLANDsSize(msg.sender);

  // Generate Tokens
  require(
    estateLandBalance.generateTokens(msg.sender, newBalance),
    "Register Balance::Could not generate tokens"
  );
}

function submitRewardsForInterval(uint32 interval) external onlyOwner {
    require(!intervalSubmitted[interval], "Interval already submitted");
    require(interval <= this.getCurrentInterval(), "Interval not finished");
    address[] memory operators = operatorsInInterval[interval].values();
    require(operators.length > 0, "No operators to reward");
    address[] memory strategies = strategiesInInterval[interval].values();
    require(strategies.length > 0, "No strategies used in the interval");

    for (uint256 i = 0; i < strategies.length; i++) {
        _submitRewardsForStrategy(interval, IStrategy(strategies[i]), operators);
    }

    intervalSubmitted[interval] = true;
    emit RewardsSubmittedForInterval(interval, operators.length);
}

function withdrawStake(uint256 _unbondingLockId) external whenSystemNotPaused currentRoundInitialized {
    Delegator storage del = delegators[msg.sender];
    UnbondingLock storage lock = del.unbondingLocks[_unbondingLockId];

    require(isValidUnbondingLock(msg.sender, _unbondingLockId), "invalid unbonding lock ID");
    require(
        lock.withdrawRound <= roundsManager().currentRound(),
        "withdraw round must be before or equal to the current round"
    );

    uint256 amount = lock.amount;
    uint256 withdrawRound = lock.withdrawRound;
    // Delete unbonding lock
    delete del.unbondingLocks[_unbondingLockId];

    // Tell Minter to transfer stake (LPT) to the delegator
    minter().trustedTransferTokens(msg.sender, amount);

    emit WithdrawStake(msg.sender, _unbondingLockId, amount, withdrawRound);
}

function buyOne() external payable nonReentrant returns (uint256) {
    uint256 amountPaidInWei = msg.value;
    require(amountPaidInWei > 0, "Amount paid must be greater than zero");

    // Price should be in [wei / NFT]
    uint256 currentPriceInWei = oracle.getMedianPrice(token.symbol());
    require(amountPaidInWei >= currentPriceInWei, "Amount paid is not enough");

    uint256 tokenId = token.mint(msg.sender);

    msg.sender.sendValue(amountPaidInWei - currentPriceInWei);

    emit TokenBought(msg.sender, tokenId, currentPriceInWei);

    return tokenId;
}

function _consumeScheduledOp(bytes32 operationId) internal virtual returns (uint32) {
    AccessManagerStorage storage $ = _getAccessManagerStorage();
    uint48 timepoint = $._schedules[operationId].timepoint;
    uint32 nonce = $._schedules[operationId].nonce;

    if (timepoint == 0) {
        revert AccessManagerNotScheduled(operationId);
    } else if (timepoint > Time.timestamp()) {
        revert AccessManagerNotReady(operationId);
    } else if (_isExpired(timepoint)) {
        revert AccessManagerExpired(operationId);
    }

    delete $._schedules[operationId].timepoint; // reset the timepoint, keep the nonce
    emit OperationExecuted(operationId, nonce);

    return nonce;
}

function _consumeScheduledOp(bytes32 operationId) internal virtual returns (uint32) {
    uint48 timepoint = _schedules[operationId].timepoint;
    uint32 nonce = _schedules[operationId].nonce;

    if (timepoint == 0) {
        revert AccessManagerNotScheduled(operationId);
    } else if (timepoint > Time.timestamp()) {
        revert AccessManagerNotReady(operationId);
    } else if (_isExpired(timepoint)) {
        revert AccessManagerExpired(operationId);
    }

    delete _schedules[operationId].timepoint; // reset the timepoint, keep the nonce
    emit OperationExecuted(operationId, nonce);

    return nonce;
}

function _approveTransfer(address from, address to, uint256 tokenId, address extension) internal {
    // Do not need to approve mints
    if (from == address(0)) return;

    if (extension != address(0) && _extensionApproveTransfers[extension]) {
        require(
            IERC721CreatorExtensionApproveTransfer(extension).approveTransfer(msg.sender, from, to, tokenId),
            "Extension approval failure"
        );
    } else if (_approveTransferBase != address(0)) {
        require(
            IERC721CreatorExtensionApproveTransfer(_approveTransferBase).approveTransfer(
                msg.sender, from, to, tokenId
            ),
            "Extension approval failure"
        );
    }
}

function permit(
    address owner,
    address spender,
    uint256 value,
    uint256 deadline,
    uint8 v,
    bytes32 r,
    bytes32 s
) public virtual {
    if (block.timestamp > deadline) {
        revert ERC2612ExpiredSignature(deadline);
    }

    bytes32 structHash = keccak256(abi.encode(PERMIT_TYPEHASH, owner, spender, value, _useNonce(owner), deadline));

    bytes32 hash = _hashTypedDataV4(structHash);

    address signer = ECDSA.recover(hash, v, r, s);
    if (signer != owner) {
        revert ERC2612InvalidSigner(signer, owner);
    }

    _approve(owner, spender, value);
}

function _toFileName(string memory name) private pure returns (string memory) {
    Vm vm = Vm(CHEATCODE_ADDRESS);
    if (name.endsWith(".sol")) {
        return name;
    } else if (name.count(":") == 1) {
        return vm.split(name, ":")[0];
    } else {
        if (name.endsWith(".json")) {
            string[] memory parts = vm.split(name, "/");
            if (parts.length > 1) {
                return parts[parts.length - 2];
            }
        }

        revert(
            string(
                abi.encodePacked(
                    "Contract name ",
                    name,
                    " must be in the format MyContract.sol:MyContract or MyContract.sol or out/MyContract.sol/MyContract.json"
                )
            )
        );
    }
}

function transferFundsToDestinations(TransferIntent calldata _intent) internal {
    if (_intent.recipientCurrency == NATIVE_CURRENCY) {
        if (_intent.recipientAmount > 0) {
            sendNative(_intent.recipient, _intent.recipientAmount, false);
        }
        if (_intent.feeAmount > 0) {
            sendNative(feeDestinations[_intent.operator], _intent.feeAmount, false);
        }
    } else {
        IERC20 requestedCurrency = IERC20(_intent.recipientCurrency);
        if (_intent.recipientAmount > 0) {
            requestedCurrency.safeTransfer(_intent.recipient, _intent.recipientAmount);
        }
        if (_intent.feeAmount > 0) {
            requestedCurrency.safeTransfer(feeDestinations[_intent.operator], _intent.feeAmount);
        }
    }
}

function makeCommitment(
    Registration calldata registration
) public pure override returns (bytes32 commitment) {
    if (registration.data.length > 0 && registration.resolver == address(0))
        revert ResolverRequiredWhenDataSupplied();

    if (
        registration.reverseRecord != 0 &&
        registration.resolver == address(0)
    ) revert ResolverRequiredForReverseRecord();

    if (registration.duration < MIN_REGISTRATION_DURATION)
        revert DurationTooShort(registration.duration);

    return keccak256(abi.encode(registration));
}

function withdrawFees(address payable _recipient, uint256 _amount)
        external
        whenSystemNotPaused
        currentRoundInitialized
        autoClaimEarnings(msg.sender)
        autoCheckpoint(msg.sender)
    {
        require(_recipient != address(0), "invalid recipient");
        uint256 fees = delegators[msg.sender].fees;
        require(fees >= _amount, "insufficient fees to withdraw");
        delegators[msg.sender].fees = fees.sub(_amount);

        // Tell Minter to transfer fees (ETH) to the address
        minter().trustedWithdrawETH(_recipient, _amount);

        emit WithdrawFees(msg.sender, _recipient, _amount);
    }

function ensureInitializedCumulativeFactorsPool(address _transcoder, uint256 _round) internal {
    Transcoder storage t = transcoders[_transcoder];
    EarningsPool.Data storage pool = t.earningsPoolPerRound[_round];
    if (pool.cumulativeRewardFactor == 0) {
        uint256 lastRewardRound = t.lastRewardRound;
        if (lastRewardRound < _round) {
            pool.cumulativeRewardFactor = cumulativeFactorsPool(t, lastRewardRound).cumulativeRewardFactor;
        }
    }
    if (pool.cumulativeFeeFactor == 0) {
        uint256 lastFeeRound = t.lastFeeRound;
        if (lastFeeRound < _round) {
            pool.cumulativeFeeFactor = cumulativeFactorsPool(t, lastFeeRound).cumulativeFeeFactor;
        }
    }
}

function updateStrategy(
    uint256 strategyId,
    bool isActive,
    uint16 newStandardProtocolFee,
    uint16 newMinTotalFee
) external onlyOwner {
    if (strategyId >= _countStrategies) {
        revert StrategyNotUsed();
    }

    if (newMinTotalFee > strategyInfo[strategyId].maxProtocolFeeBp || newStandardProtocolFee > newMinTotalFee) {
        revert StrategyProtocolFeeTooHigh();
    }

    strategyInfo[strategyId].isActive = isActive;
    strategyInfo[strategyId].standardProtocolFeeBp = newStandardProtocolFee;
    strategyInfo[strategyId].minTotalFeeBp = newMinTotalFee;

    emit StrategyUpdated(strategyId, isActive, newStandardProtocolFee, newMinTotalFee);
}

function _setAssetHandlerAddressThisChain(
    address _nativeTokenVault,
    bytes32 _assetRegistrationData,
    address _assetHandlerAddress
) internal {
    bool senderIsNTV = msg.sender == _nativeTokenVault;
    address sender = senderIsNTV ? L2_NATIVE_TOKEN_VAULT_ADDR : msg.sender;
    bytes32 assetId = DataEncoding.encodeAssetId(block.chainid, _assetRegistrationData, sender);
    if (!senderIsNTV && msg.sender != assetDeploymentTracker[assetId]) {
        revert Unauthorized(msg.sender);
    }
    _setAssetHandler(assetId, _assetHandlerAddress);
    assetDeploymentTracker[assetId] = msg.sender;
    emit AssetDeploymentTrackerRegistered(assetId, _assetRegistrationData, msg.sender);
}

function flashLoan(address payable borrower, uint256 borrowAmount) external nonReentrant {

    uint256 balanceBefore = address(this).balance;
    require(balanceBefore >= borrowAmount, "Not enough ETH in pool");


    require(address(borrower).isContract(), "Borrower must be a deployed contract");
    // Transfer ETH and handle control to receiver
    (bool success, ) = borrower.call{value: borrowAmount}(
        abi.encodeWithSignature(
            "receiveEther(uint256)",
            FIXED_FEE
        )
    );
    require(success, "External call failed");

    require(
        address(this).balance >= balanceBefore.add(FIXED_FEE),
        "Flash loan hasn't been paid back"
    );
}

function join(externalEuint64 externalAmount, bytes calldata inputProof) public virtual returns (euint64) {
    euint64 amount = FHE.fromExternal(externalAmount, inputProof);
    FHE.allowTransient(amount, address(fromToken()));
    euint64 transferred = fromToken().confidentialTransferFrom(msg.sender, address(this), amount);

    euint64 joinedAmount = _join(msg.sender, transferred);
    euint64 refundAmount = FHE.sub(transferred, joinedAmount);

    FHE.allowTransient(refundAmount, address(fromToken()));

    fromToken().confidentialTransfer(msg.sender, refundAmount);

    return joinedAmount;
}

function _setPendingDelay(uint48 newDelay, uint48 newSchedule) private {
    AccessControlDefaultAdminRulesStorage storage $ = _getAccessControlDefaultAdminRulesStorage();
    uint48 oldSchedule = $._pendingDelaySchedule;

    if (_isScheduleSet(oldSchedule)) {
        if (_hasSchedulePassed(oldSchedule)) {
            // Materialize a virtual delay
            $._currentDelay = $._pendingDelay;
        } else {
            // Emit for implicit cancellations when another delay was scheduled.
            emit DefaultAdminDelayChangeCanceled();
        }
    }

    $._pendingDelay = newDelay;
    $._pendingDelaySchedule = newSchedule;
}

function _setLink(address gateway, bytes memory counterpart, bool allowOverride) internal virtual {
    CrosschainLinkedStorage storage $ = _getCrosschainLinkedStorage();
    // Sanity check, this should revert if gateway is not an ERC-7786 implementation. Note that since
    // supportsAttribute returns data, an EOA would fail that test (nothing returned).
    IERC7786GatewaySource(gateway).supportsAttribute(bytes4(0));

    bytes memory chain = _extractChain(counterpart);
    if (allowOverride || $._links[chain].gateway == address(0)) {
        $._links[chain] = Link(gateway, counterpart);
        emit LinkRegistered(gateway, counterpart);
    } else {
        revert LinkAlreadyRegistered(chain);
    }
}

function remove(List storage list, bytes32 key) internal {
  Element storage element = list.elements[key];
  require(key != bytes32(0) && contains(list, key), "key not in list");
  if (element.previousKey != bytes32(0)) {
    Element storage previousElement = list.elements[element.previousKey];
    previousElement.nextKey = element.nextKey;
  } else {
    list.tail = element.nextKey;
  }

  if (element.nextKey != bytes32(0)) {
    Element storage nextElement = list.elements[element.nextKey];
    nextElement.previousKey = element.previousKey;
  } else {
    list.head = element.previousKey;
  }

  delete list.elements[key];
  list.numElements = list.numElements.sub(1);
}

function revokePending(
  address group,
  uint256 value,
  address lesser,
  address greater,
  uint256 index
) external nonReentrant returns (bool) {
  require(group != address(0), "Group address zero");
  address account = getAccounts().voteSignerToAccount(msg.sender);
  require(0 < value, "Vote value cannot be zero");
  require(
    value <= getPendingVotesForGroupByAccount(group, account),
    "Vote value larger than pending votes"
  );
  decrementPendingVotes(group, account, value);
  decrementTotalVotes(account, group, value, lesser, greater);
  getLockedGold().incrementNonvotingAccountBalance(account, value);
  if (getTotalVotesForGroupByAccount(group, account) == 0) {
    deleteElement(votes.groupsVotedFor[account], group, index);
  }
  emit ValidatorGroupPendingVoteRevoked(account, group, value);
  return true;
}

function createPartyWithMetadata(
    Party partyImpl,
    address[] memory authorities,
    Party.PartyOptions memory opts,
    IERC721[] memory preciousTokens,
    uint256[] memory preciousTokenIds,
    uint40 rageQuitTimestamp,
    MetadataProvider provider,
    bytes memory metadata
) external returns (Party party) {
    party = createParty(
        partyImpl,
        authorities,
        opts,
        preciousTokens,
        preciousTokenIds,
        rageQuitTimestamp
    );

    MetadataRegistry registry = MetadataRegistry(
        _GLOBALS.getAddress(LibGlobals.GLOBAL_METADATA_REGISTRY)
    );

    // Set the metadata for the Party.
    registry.setProvider(address(party), provider);
    if (metadata.length > 0) provider.setMetadata(address(party), metadata);
}

function initialize(
    address _owner,
    uint256 _eraPostDiamondUpgradeFirstBatch,
    uint256 _eraPostLegacyBridgeUpgradeFirstBatch,
    uint256 _eraLegacyBridgeLastDepositBatch,
    uint256 _eraLegacyBridgeLastDepositTxNumber
) external reentrancyGuardInitializer initializer {
    if (_owner == address(0)) {
        revert ZeroAddress();
    }
    _transferOwnership(_owner);
    if (eraPostDiamondUpgradeFirstBatch == 0) {
        eraPostDiamondUpgradeFirstBatch = _eraPostDiamondUpgradeFirstBatch;
        eraPostLegacyBridgeUpgradeFirstBatch = _eraPostLegacyBridgeUpgradeFirstBatch;
        eraLegacyBridgeLastDepositBatch = _eraLegacyBridgeLastDepositBatch;
        eraLegacyBridgeLastDepositTxNumber = _eraLegacyBridgeLastDepositTxNumber;
    }
}

function deployCounterpartToken(TokenDescription memory tokenDesc, uint256 height, bytes memory proof)
        external
        returns (address deployedToken)
    {
        bytes32 id = _generateTokenDescriptionId(tokenDesc);
        require(!_processed[id], CounterpartTokenAlreadyDeployed());
        require(
            _counterpartTokens[tokenDesc.originalToken] == address(0),
            "Counterpart token already exists for this original token"
        );

        signalService.verifySignal(height, trustedCommitmentPublisher, counterpart, id, proof);

        deployedToken = address(new BridgedERC1155(tokenDesc.uri, tokenDesc.originalToken));
        _counterpartTokens[tokenDesc.originalToken] = deployedToken;
        _isBridgedTokens[deployedToken] = true;
        _processed[id] = true;

        emit CounterpartTokenDeployed(id, tokenDesc, deployedToken);
    }
